CREATE TABLE IF NOT EXISTS roles (id SERIAL PRIMARY KEY,nombre VARCHAR(80) UNIQUE NOT NULL,descripcion TEXT);
CREATE TABLE IF NOT EXISTS usuarios (id SERIAL PRIMARY KEY,nombre VARCHAR(120) NOT NULL,email VARCHAR(160) UNIQUE NOT NULL,password_hash VARCHAR(255) NOT NULL,activo BOOLEAN DEFAULT TRUE,role_id INT REFERENCES roles(id),creado_en TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS barrios (id SERIAL PRIMARY KEY,nombre VARCHAR(120) UNIQUE NOT NULL,poblacion_estimada INT DEFAULT 0,estrato_promedio NUMERIC DEFAULT 0,lat NUMERIC,lng NUMERIC,geojson JSONB);
CREATE TABLE IF NOT EXISTS veredas (id SERIAL PRIMARY KEY,nombre VARCHAR(120) UNIQUE NOT NULL,poblacion_estimada INT DEFAULT 0,lat NUMERIC,lng NUMERIC,geojson JSONB);
CREATE TABLE IF NOT EXISTS puestos_votacion (id SERIAL PRIMARY KEY,nombre VARCHAR(180) NOT NULL,direccion VARCHAR(220),mesas INT DEFAULT 0,potencial INT DEFAULT 0,lat NUMERIC,lng NUMERIC,barrio_id INT REFERENCES barrios(id),vereda_id INT REFERENCES veredas(id));
CREATE TABLE IF NOT EXISTS elecciones (id SERIAL PRIMARY KEY,nombre VARCHAR(160) NOT NULL,tipo VARCHAR(80) NOT NULL,anio INT NOT NULL,total_votos INT DEFAULT 0,censo_electoral INT DEFAULT 0);
CREATE TABLE IF NOT EXISTS resultados_electorales (id SERIAL PRIMARY KEY,eleccion_id INT NOT NULL REFERENCES elecciones(id),candidato VARCHAR(160) NOT NULL,partido VARCHAR(160),votos INT DEFAULT 0,sector VARCHAR(160),puesto_id INT REFERENCES puestos_votacion(id));
CREATE TABLE IF NOT EXISTS indicadores_demograficos (id SERIAL PRIMARY KEY,anio INT NOT NULL,grupo VARCHAR(80) NOT NULL,sexo VARCHAR(30),valor INT DEFAULT 0,barrio_id INT REFERENCES barrios(id),vereda_id INT REFERENCES veredas(id));
CREATE TABLE IF NOT EXISTS problematicas (id SERIAL PRIMARY KEY,categoria VARCHAR(80) NOT NULL,descripcion TEXT,severidad INT DEFAULT 1,frecuencia INT DEFAULT 1,fuente VARCHAR(120),evidencia TEXT,responsable VARCHAR(120),estado VARCHAR(40) DEFAULT 'abierta',lat NUMERIC,lng NUMERIC,barrio_id INT REFERENCES barrios(id),vereda_id INT REFERENCES veredas(id),fecha TIMESTAMP DEFAULT NOW(),fecha_actualizacion TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS ciudadanos_captados (id SERIAL PRIMARY KEY,nombres VARCHAR(120) NOT NULL,apellidos VARCHAR(120) NOT NULL,tipo_documento VARCHAR(30),numero_documento VARCHAR(50) UNIQUE,telefono VARCHAR(50),email VARCHAR(160),barrio_id INT REFERENCES barrios(id),vereda_id INT REFERENCES veredas(id),direccion_referencia VARCHAR(220),edad INT,sexo VARCHAR(30),ocupacion VARCHAR(120),segmento VARCHAR(120),fuente_captura VARCHAR(120) NOT NULL,lider_responsable VARCHAR(120),consentimiento_datos BOOLEAN NOT NULL DEFAULT FALSE,fecha_consentimiento TIMESTAMP,observaciones TEXT,estado_contacto VARCHAR(60) DEFAULT 'pendiente',nivel_apoyo VARCHAR(30) DEFAULT 'indeciso',fecha_creacion TIMESTAMP DEFAULT NOW(),fecha_actualizacion TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS interacciones_territoriales (id SERIAL PRIMARY KEY,ciudadano_id INT REFERENCES ciudadanos_captados(id),barrio_id INT REFERENCES barrios(id),vereda_id INT REFERENCES veredas(id),tipo_interaccion VARCHAR(80) NOT NULL,canal VARCHAR(40) NOT NULL,tema VARCHAR(160),descripcion TEXT,responsable VARCHAR(120),fecha TIMESTAMP NOT NULL,resultado TEXT,requiere_seguimiento BOOLEAN DEFAULT FALSE,fecha_seguimiento TIMESTAMP,fecha_creacion TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS segmentos (id SERIAL PRIMARY KEY,nombre VARCHAR(120) NOT NULL,descripcion TEXT,tamano_estimado INT DEFAULT 0,participacion_historica NUMERIC DEFAULT 0,necesidades TEXT);
CREATE TABLE IF NOT EXISTS proyecciones (id SERIAL PRIMARY KEY,nombre VARCHAR(120) NOT NULL,parametros JSONB NOT NULL,resultados JSONB NOT NULL,creado_en TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS reportes (id SERIAL PRIMARY KEY,tipo VARCHAR(80) NOT NULL,titulo VARCHAR(160) NOT NULL,ruta VARCHAR(250),creado_en TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS auditoria (id SERIAL PRIMARY KEY,usuario_id INT REFERENCES usuarios(id),accion VARCHAR(160) NOT NULL,entidad VARCHAR(100),detalle JSONB,creado_en TIMESTAMP DEFAULT NOW());
INSERT INTO roles(nombre) VALUES ('Administrador'),('Analista'),('Coordinador Territorial') ON CONFLICT DO NOTHING;
